export declare const welcomeText = "\uD83D\uDEC2 <b>Pro Visa</b>\n\n\u0412\u0430\u0448 \u043F\u0435\u0440\u0441\u043E\u043D\u0430\u043B\u044C\u043D\u044B\u0439 \u0432\u0438\u0437\u043E\u0432\u044B\u0439 \u043F\u043E\u043C\u043E\u0449\u043D\u0438\u043A: AI-\u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0430 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u0438 \u043D\u0430\u043F\u043E\u043C\u0438\u043D\u0430\u043D\u0438\u044F \u043E\u0431 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F\u0445 \u0432 \u0432\u0438\u0437\u043E\u0432\u043E\u0439 \u043F\u043E\u043B\u0438\u0442\u0438\u043A\u0435.\n\n<b>\u0411\u044B\u0441\u0442\u0440\u044B\u0439 \u0441\u0442\u0430\u0440\u0442</b>\n\u2022 \u0417\u0430\u0433\u0440\u0443\u0437\u0438\u0442\u0435 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u044B \u2014 \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u0435 \u043E\u0446\u0435\u043D\u043A\u0443 \u0437\u0430 ~30 \u0441\u0435\u043A\u0443\u043D\u0434\n\u2022 \u041F\u043E\u0434\u043F\u0438\u0448\u0438\u0442\u0435\u0441\u044C \u043D\u0430 \u043E\u0431\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u044F \u043F\u043E \u0432\u044B\u0431\u0440\u0430\u043D\u043D\u044B\u043C \u0441\u0442\u0440\u0430\u043D\u0430\u043C\n\u2022 \u0417\u0430\u043A\u0430\u0436\u0438\u0442\u0435 \u043A\u043E\u043D\u0441\u0443\u043B\u044C\u0442\u0430\u0446\u0438\u044E \u0441 \u044D\u043A\u0441\u043F\u0435\u0440\u0442\u043E\u043C\n\n\u041D\u0430\u0436\u043C\u0438\u0442\u0435 \u043A\u043D\u043E\u043F\u043A\u0443 \u043D\u0438\u0436\u0435 \u0438\u043B\u0438 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u0443\u0439\u0442\u0435 \u043A\u043E\u043C\u0430\u043D\u0434\u044B \u043C\u0435\u043D\u044E.";
export declare const documentsText = "\uD83D\uDCC4 <b>\u0414\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u044B</b>\n\n\u2022 <b>\u0427\u0435\u043A-\u043B\u0438\u0441\u0442 \u043F\u043E \u0441\u0442\u0440\u0430\u043D\u0430\u043C</b> \u2014 \u043A\u043E\u043C\u0430\u043D\u0434\u0430 /countries \u0438\u043B\u0438 \u043A\u043D\u043E\u043F\u043A\u0430 \u00AB\uD83D\uDDFA \u0421\u0442\u0440\u0430\u043D\u044B\u00BB\n\u2022 <b>AI-\u043F\u0440\u043E\u0432\u0435\u0440\u043A\u0430 \u0441\u043A\u0430\u043D\u043E\u0432</b> \u2014 Mini App \u2192 \u00AB\u0414\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u044B\u00BB\n\n\u0412\u044B\u0431\u0435\u0440\u0438\u0442\u0435 \u0441\u0442\u0440\u0430\u043D\u0443, \u0447\u0442\u043E\u0431\u044B \u0443\u0432\u0438\u0434\u0435\u0442\u044C \u0441\u043F\u0438\u0441\u043E\u043A \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u043F\u043E \u0442\u0438\u043F\u0443 \u0432\u0438\u0437\u044B.";
export declare const countriesIntroText = "\uD83D\uDDFA <b>\u0414\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u044B \u043F\u043E \u0441\u0442\u0440\u0430\u043D\u0430\u043C</b>\n\n\u0412\u044B\u0431\u0435\u0440\u0438\u0442\u0435 \u0441\u0442\u0440\u0430\u043D\u0443 \u2014 \u043F\u043E\u043A\u0430\u0436\u0435\u043C \u043F\u0430\u043A\u0435\u0442 \u0434\u043E\u043A\u0443\u043C\u0435\u043D\u0442\u043E\u0432 \u0434\u043B\u044F \u0442\u0443\u0440\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0438 \u0434\u0440\u0443\u0433\u0438\u0445 \u043F\u043E\u043F\u0443\u043B\u044F\u0440\u043D\u044B\u0445 \u0432\u0438\u0437.\n\n\u0414\u0430\u043D\u043D\u044B\u0435 \u0441\u043F\u0440\u0430\u0432\u043E\u0447\u043D\u044B\u0435; \u043F\u0435\u0440\u0435\u0434 \u043F\u043E\u0434\u0430\u0447\u0435\u0439 \u0443\u0442\u043E\u0447\u043D\u044F\u0439\u0442\u0435 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u0432 \u043A\u043E\u043D\u0441\u0443\u043B\u044C\u0441\u0442\u0432\u0435.";
export declare const updatesText = "\uD83C\uDF0D <b>\u0412\u0438\u0437\u043E\u0432\u044B\u0435 \u043D\u043E\u0432\u043E\u0441\u0442\u0438</b>\n\n\u0410\u043A\u0442\u0443\u0430\u043B\u044C\u043D\u044B\u0435 \u0438\u0437\u043C\u0435\u043D\u0435\u043D\u0438\u044F \u043F\u043E \u0441\u0440\u043E\u043A\u0430\u043C, \u0441\u0431\u043E\u0440\u0430\u043C \u0438 \u043F\u0440\u0430\u0432\u0438\u043B\u0430\u043C \u043F\u043E\u0434\u0430\u0447\u0438.\n\n\u041D\u0430\u0436\u043C\u0438\u0442\u0435 \u043A\u043D\u043E\u043F\u043A\u0443 \u043D\u0438\u0436\u0435 \u0434\u043B\u044F \u0434\u0430\u0439\u0434\u0436\u0435\u0441\u0442\u0430 \u0438\u043B\u0438 \u043E\u0442\u043A\u0440\u043E\u0439\u0442\u0435 Mini App \u2192 \u00AB\u041E\u0431\u043D\u043E\u0432\u043B\u0435\u043D\u0438\u044F\u00BB \u0441 \u0444\u0438\u043B\u044C\u0442\u0440\u043E\u043C \u043F\u043E \u0441\u0442\u0440\u0430\u043D\u0430\u043C.";
export declare const consultText = "\uD83D\uDC64 <b>\u041A\u043E\u043D\u0441\u0443\u043B\u044C\u0442\u0430\u0446\u0438\u044F \u0441 \u044D\u043A\u0441\u043F\u0435\u0440\u0442\u043E\u043C</b>\n\n\u041D\u0430\u043F\u0438\u0448\u0438\u0442\u0435 \u0432\u043E\u043F\u0440\u043E\u0441 \u0432 \u0447\u0430\u0442 \u0438\u043B\u0438 \u043E\u0442\u043F\u0440\u0430\u0432\u044C\u0442\u0435 \u043D\u043E\u043C\u0435\u0440 \u0442\u0435\u043B\u0435\u0444\u043E\u043D\u0430 \u2014 \u0437\u0430\u044F\u0432\u043A\u0430 \u043F\u0440\u0438\u0434\u0451\u0442 \u0441\u043F\u0435\u0446\u0438\u0430\u043B\u0438\u0441\u0442\u0443.\n\n\u041A\u043E\u043C\u0430\u043D\u0434\u0430 /consult \u2014 \u0442\u043E \u0436\u0435 \u0441\u0430\u043C\u043E\u0435.";
